import React, { useEffect, useState } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";
import EditProfile from "../users/EditProfile";

export default function AdminProfile() {
  const navigate = useNavigate();

  const [user, setUser] = useState(null);
  const [showEditProfile, setShowEditProfile] = useState(false);

  useEffect(() => {
    const raw = localStorage.getItem("user");
    const stored = raw ? JSON.parse(raw) : null;

    if (!stored?.email) return;

    axios
      .get(`http://localhost:8086/user/profile?email=${stored.email}`)
      .then((res) => setUser(res.data))
      .catch((err) => console.log(err));
  }, []);

  if (!user) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gray-100">
        <div className="text-gray-600 font-medium">Loading admin profile...</div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-100 p-8 ml-[17vw]">

      {/* PAGE HEADER */}
      <div className="mb-6">
        <h1 className="text-2xl font-bold text-gray-800">
          Admin Profile
        </h1>
        <p className="text-gray-500 text-sm">
          Manage account details and system access
        </p>
      </div>

      {/* MAIN CARD */}
      <div className="grid grid-cols-3 gap-6">

        {/* LEFT PROFILE CARD */}
        <div className="col-span-1 bg-white rounded-2xl shadow-md p-6 flex flex-col items-center">

          <img
            src={
              user.profileImage ||
              `https://ui-avatars.com/api/?name=${user.username}`
            }
            alt="profile"
            className="w-28 h-28 rounded-full object-cover border-4 border-indigo-500"
          />

          <h2 className="mt-4 text-xl font-bold text-gray-800">
            {user.name}
          </h2>

          <p className="text-gray-500 text-sm">{user.email}</p>

          <span className="mt-2 px-3 py-1 text-xs bg-indigo-100 text-indigo-700 rounded-full">
            {user.role}
          </span>

          <div className="w-full mt-6 space-y-3">

            <button
              onClick={() => setShowEditProfile(true)}
              className="w-full bg-indigo-600 text-white py-2 rounded-lg hover:bg-indigo-700 transition"
            >
              Edit Profile
            </button>

            <button
              onClick={() => {
                localStorage.clear();
                navigate("/");
                window.location.reload();
              }}
              className="w-full bg-red-500 text-white py-2 rounded-lg hover:bg-red-600 transition"
            >
              Logout
            </button>

          </div>
        </div>

        {/* RIGHT INFO PANEL */}
        <div className="col-span-2 space-y-6">

          {/* INFO GRID */}
          <div className="grid grid-cols-2 gap-4">

            <div className="bg-white p-4 rounded-xl shadow">
              <p className="text-gray-500 text-sm">Username</p>
              <p className="font-semibold">{user.username}</p>
            </div>

            <div className="bg-white p-4 rounded-xl shadow">
              <p className="text-gray-500 text-sm">Role</p>
              <p className="font-semibold">{user.role}</p>
            </div>

            <div className="bg-white p-4 rounded-xl shadow">
              <p className="text-gray-500 text-sm">Email Status</p>
              <p className="font-semibold text-green-600">Verified</p>
            </div>

            <div className="bg-white p-4 rounded-xl shadow">
              <p className="text-gray-500 text-sm">Account Type</p>
              <p className="font-semibold">System Admin</p>
            </div>

          </div>

          {/* ADMIN STATS (optional feel) */}
          <div className="bg-white p-6 rounded-2xl shadow">
            <h3 className="font-bold text-gray-800 mb-4">
              System Overview
            </h3>

            <div className="grid grid-cols-3 gap-4">

              <div className="bg-gray-50 p-4 rounded-xl text-center">
                <p className="text-2xl font-bold text-indigo-600">128</p>
                <p className="text-sm text-gray-500">Users</p>
              </div>

              <div className="bg-gray-50 p-4 rounded-xl text-center">
                <p className="text-2xl font-bold text-indigo-600">24</p>
                <p className="text-sm text-gray-500">Courses</p>
              </div>

              <div className="bg-gray-50 p-4 rounded-xl text-center">
                <p className="text-2xl font-bold text-indigo-600">7</p>
                <p className="text-sm text-gray-500">Reports</p>
              </div>

            </div>
          </div>

        </div>
      </div>

      {/* EDIT MODAL */}
      {showEditProfile && (
        <div className="fixed inset-0 flex items-center justify-center z-50">
          <div
            className="absolute inset-0 bg-black/40"
            onClick={() => setShowEditProfile(false)}
          />
          <div className="relative z-50">
            <EditProfile closeModal={() => setShowEditProfile(false)} />
          </div>
        </div>
      )}

    </div>
  );
}
